import React, { useEffect, useState } from 'react';
import { getAppointments, getPatients, getDoctors, createAppointment, deleteAppointment } from '../api';
import { Appointment, Patient, Doctor } from '../types';

const AppointmentList: React.FC = () => {
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [patients, setPatients] = useState<Patient[]>([]);
    const [doctors, setDoctors] = useState<Doctor[]>([]);
    const [formData, setFormData] = useState({ patient: '', doctor: '', appointment_date: '', status: 'Scheduled' });

    useEffect(() => { load(); }, []);
    const load = async () => {
        const [a, p, d] = await Promise.all([getAppointments(), getPatients(), getDoctors()]);
        setAppointments(a.data); setPatients(p.data); setDoctors(d.data);
    };

    const handleSchedule = async () => {
        try {
            await createAppointment(formData);
            setFormData({ patient: '', doctor: '', appointment_date: '', status: 'Scheduled' });
            load();
        } catch (err) { alert("Please select both Patient and Doctor."); }
    };

    return (
        <div className="p-6 bg-white rounded-lg shadow-sm">
            <h2 className="text-xl font-semibold mb-4">Scheduled Appointments</h2>
            <div className="flex gap-2 mb-6 bg-gray-50 p-4 rounded">
                <select value={formData.patient} onChange={e => setFormData({...formData, patient: e.target.value})} className="border p-2 flex-1 rounded">
                    <option value="">Select Patient</option>
                    {patients.map(p => <option key={p.patient_id} value={p.patient_id}>{p.first_name} {p.last_name}</option>)}
                </select>
                <select value={formData.doctor} onChange={e => setFormData({...formData, doctor: e.target.value})} className="border p-2 flex-1 rounded">
                    <option value="">Select Doctor</option>
                    {doctors.map(d => <option key={d.doctor_id} value={d.doctor_id}>Dr. {d.last_name}</option>)}
                </select>
                <input type="datetime-local" value={formData.appointment_date} onChange={e => setFormData({...formData, appointment_date: e.target.value})} className="border p-2 rounded" />
                <button onClick={handleSchedule} className="bg-indigo-600 text-white px-6 py-2 rounded font-bold">Schedule</button>
            </div>
            <table className="w-full text-left border-t">
                <thead className="bg-gray-50"><tr><th className="p-3">ID</th><th className="p-3">Schedule</th><th className="p-3">Status</th></tr></thead>
                <tbody>{appointments.map(a => (
                    <tr key={a.appointment_id} className="border-b">
                        <td className="p-3">{a.appointment_id}</td>
                        <td className="p-3">{new Date(a.appointment_date).toLocaleString()}</td>
                        <td className="p-3">{a.status}</td>
                    </tr>
                ))}</tbody>
            </table>
        </div>
    );
};
export default AppointmentList;
